    53  void HttpGrpcAccessLog::emitLog(const Formatter::HttpFormatterContext& context,
    54                                  const StreamInfo::StreamInfo& stream_info) {
    55    // Common log properties.
    56    // TODO(mattklein123): Populate sample_rate field.
    57    envoy::data::accesslog::v3::HTTPAccessLogEntry log_entry;
    58
    59    const auto& request_headers = context.requestHeaders();
    60
    61    GrpcCommon::Utility::extractCommonAccessLogProperties(
    62        *log_entry.mutable_common_properties(), request_headers, stream_info,
    63        config_->common_config(), context.accessLogType());
    64
    65    if (stream_info.protocol()) {
    66      switch (stream_info.protocol().value()) {
    67      case Http::Protocol::Http10:
    68        log_entry.set_protocol_version(envoy::data::accesslog::v3::HTTPAccessLogEntry::HTTP10);
    69        break;
    70      case Http::Protocol::Http11:
    71        log_entry.set_protocol_version(envoy::data::accesslog::v3::HTTPAccessLogEntry::HTTP11);
    72        break;
    73      case Http::Protocol::Http2:
    74        log_entry.set_protocol_version(envoy::data::accesslog::v3::HTTPAccessLogEntry::HTTP2);
    75        break;
    76      case Http::Protocol::Http3:
    77        log_entry.set_protocol_version(envoy::data::accesslog::v3::HTTPAccessLogEntry::HTTP3);
    78        break;
    79      }
    80    }
    81
    82    // HTTP request properties.
    83    // TODO(mattklein123): Populate port field.
    84    auto* request_properties = log_entry.mutable_request();
    85    if (request_headers.Scheme() != nullptr) {
    86      request_properties->set_scheme(
    87          MessageUtil::sanitizeUtf8String(request_headers.getSchemeValue()));
    88    }
    89    if (request_headers.Host() != nullptr) {
    90      request_properties->set_authority(
    91          MessageUtil::sanitizeUtf8String(request_headers.getHostValue()));
    92    }
    93    if (request_headers.Path() != nullptr) {
    94      request_properties->set_path(MessageUtil::sanitizeUtf8String(request_headers.getPathValue()));
    95    }
    96    if (request_headers.UserAgent() != nullptr) {
    97      request_properties->set_user_agent(
    98          MessageUtil::sanitizeUtf8String(request_headers.getUserAgentValue()));
    99    }
   100    if (request_headers.getInline(referer_handle.handle()) != nullptr) {
   101      request_properties->set_referer(
   102          MessageUtil::sanitizeUtf8String(request_headers.getInlineValue(referer_handle.handle())));
   103    }
   104    if (request_headers.ForwardedFor() != nullptr) {
   105      request_properties->set_forwarded_for(
   106          MessageUtil::sanitizeUtf8String(request_headers.getForwardedForValue()));
   107    }
   108    if (request_headers.RequestId() != nullptr) {
   109      request_properties->set_request_id(
   110          MessageUtil::sanitizeUtf8String(request_headers.getRequestIdValue()));
   111    }
   112    if (request_headers.EnvoyOriginalPath() != nullptr) {
   113      request_properties->set_original_path(
   114          MessageUtil::sanitizeUtf8String(request_headers.getEnvoyOriginalPathValue()));
   115    }
   116    request_properties->set_request_headers_bytes(request_headers.byteSize());
   117    request_properties->set_request_body_bytes(stream_info.bytesReceived());
   118
   119    if (request_headers.Method() != nullptr) {
   120      envoy::config::core::v3::RequestMethod method = envoy::config::core::v3::METHOD_UNSPECIFIED;
   121      envoy::config::core::v3::RequestMethod_Parse(
   122          MessageUtil::sanitizeUtf8String(request_headers.getMethodValue()), &method);
   123      request_properties->set_request_method(method);
   124    }
   125    if (!request_headers_to_log_.empty()) {
   126      auto* logged_headers = request_properties->mutable_request_headers();
   127
   128      for (const auto& header : request_headers_to_log_) {
   129        const auto all_values = Http::HeaderUtility::getAllOfHeaderAsString(request_headers, header);
   130        if (all_values.result().has_value()) {
   131          logged_headers->insert(
   132              {header.get(), MessageUtil::sanitizeUtf8String(all_values.result().value())});
   133        }
   134      }
   135    }
   136
   137    // HTTP response properties.
   138    const auto& response_headers = context.responseHeaders();
   139    const auto& response_trailers = context.responseTrailers();
   140
   141    auto* response_properties = log_entry.mutable_response();
   142    if (stream_info.responseCode()) {
   143      response_properties->mutable_response_code()->set_value(stream_info.responseCode().value());
   144    }
   145    if (stream_info.responseCodeDetails()) {
   146      response_properties->set_response_code_details(stream_info.responseCodeDetails().value());
   147    }
   148    response_properties->set_response_headers_bytes(response_headers.byteSize());
   149    response_properties->set_response_body_bytes(stream_info.bytesSent());
   150    if (!response_headers_to_log_.empty()) {
   151      auto* logged_headers = response_properties->mutable_response_headers();
   152
   153      for (const auto& header : response_headers_to_log_) {
   154        const auto all_values = Http::HeaderUtility::getAllOfHeaderAsString(response_headers, header);
   155        if (all_values.result().has_value()) {
   156          logged_headers->insert(
   157              {header.get(), MessageUtil::sanitizeUtf8String(all_values.result().value())});
   158        }
   159      }
   160    }
   161
   162    if (!response_trailers_to_log_.empty()) {
   163      auto* logged_headers = response_properties->mutable_response_trailers();
   164
   165      for (const auto& header : response_trailers_to_log_) {
   166        const auto all_values =
   167            Http::HeaderUtility::getAllOfHeaderAsString(response_trailers, header);
   168        if (all_values.result().has_value()) {
   169          logged_headers->insert(
   170              {header.get(), MessageUtil::sanitizeUtf8String(all_values.result().value())});
   171        }
   172      }
   173    }
   174
   175    if (const auto& bytes_meter = stream_info.getDownstreamBytesMeter(); bytes_meter != nullptr) {
   176      request_properties->set_downstream_header_bytes_received(bytes_meter->headerBytesReceived());
   177      response_properties->set_downstream_header_bytes_sent(bytes_meter->headerBytesSent());
   178    }
   179    if (const auto& bytes_meter = stream_info.getUpstreamBytesMeter(); bytes_meter != nullptr) {
   180      request_properties->set_upstream_header_bytes_sent(bytes_meter->headerBytesSent());
   181      response_properties->set_upstream_header_bytes_received(bytes_meter->headerBytesReceived());
   182    }
   183
   184    tls_slot_->getTyped<ThreadLocalLogger>().logger_->log(std::move(log_entry));
   185  }
