    25  // Used to pack/unpack the body AnyValue to a KeyValueList.
    26  const char BODY_KEY[] = "body";
    27
    28  namespace Envoy {
    29  namespace Extensions {
    30  namespace AccessLoggers {
    31  namespace OpenTelemetry {
    32
    33  namespace {
    34
    35  // Packing the body "AnyValue" to a "KeyValueList" with a single key and the body as value.
    36  ::opentelemetry::proto::common::v1::KeyValueList
    37  packBody(const ::opentelemetry::proto::common::v1::AnyValue& body) {
    38    ::opentelemetry::proto::common::v1::KeyValueList output;
    39    auto* kv = output.add_values();
    40    kv->set_key(BODY_KEY);
    41    *kv->mutable_value() = body;
    42    return output;
    43  }
    44
    45  ::opentelemetry::proto::common::v1::AnyValue
    46  unpackBody(const ::opentelemetry::proto::common::v1::KeyValueList& value) {
    47    ASSERT(value.values().size() == 1 && value.values(0).key() == BODY_KEY);
    48    return value.values(0).value();
    49  }
    50
    51  } // namespace
    52
    53  Http::RegisterCustomInlineHeader<Http::CustomInlineHeaderRegistry::Type::RequestHeaders>
    54      referer_handle(Http::CustomHeaders::get().Referer);
    55
    56  AccessLog::ThreadLocalLogger::ThreadLocalLogger(GrpcAccessLoggerSharedPtr logger)
    57      : logger_(std::move(logger)) {}
    58
    59  AccessLog::AccessLog(
    60      ::Envoy::AccessLog::FilterPtr&& filter,
    61      envoy::extensions::access_loggers::open_telemetry::v3::OpenTelemetryAccessLogConfig config,
    62      ThreadLocal::SlotAllocator& tls, GrpcAccessLoggerCacheSharedPtr access_logger_cache,
    63      const std::vector<Formatter::CommandParserPtr>& commands)
    64      : Common::ImplBase(std::move(filter)), tls_slot_(tls.allocateSlot()),
    65        access_logger_cache_(std::move(access_logger_cache)) {
    66
    67    THROW_IF_NOT_OK(Envoy::Config::Utility::checkTransportVersion(config.common_config()));
    68    tls_slot_->set([this, config](Event::Dispatcher&) {
    69      return std::make_shared<ThreadLocalLogger>(
    70          access_logger_cache_->getOrCreateLogger(config, Common::GrpcAccessLoggerType::HTTP));
    71    });
    72
    73    // Packing the body "AnyValue" to a "KeyValueList" only if it's not empty, otherwise the
    74    // formatter would fail to parse it.
    75    if (config.body().value_case() != ::opentelemetry::proto::common::v1::AnyValue::VALUE_NOT_SET) {
    76      body_formatter_ = std::make_unique<OpenTelemetryFormatter>(packBody(config.body()), commands);
    77    }
    78    attributes_formatter_ = std::make_unique<OpenTelemetryFormatter>(config.attributes(), commands);
    79  }
    80
    81  void AccessLog::emitLog(const Formatter::HttpFormatterContext& log_context,
    82                          const StreamInfo::StreamInfo& stream_info) {
    83    opentelemetry::proto::logs::v1::LogRecord log_entry;
    84    log_entry.set_time_unix_nano(std::chrono::duration_cast<std::chrono::nanoseconds>(
    85                                     stream_info.startTime().time_since_epoch())
    86                                     .count());
    87
    88    // Unpacking the body "KeyValueList" to "AnyValue".
    89    if (body_formatter_) {
    90      const auto formatted_body = unpackBody(body_formatter_->format(log_context, stream_info));
    91      *log_entry.mutable_body() = formatted_body;
    92    }
    93    const auto formatted_attributes = attributes_formatter_->format(log_context, stream_info);
    94    *log_entry.mutable_attributes() = formatted_attributes.values();
    95
    96    // Setting the trace id if available.
    97    // OpenTelemetry trace id is a [16]byte array, backend(e.g. OTel-collector) will reject the
    98    // request if the length is not 16. Some trace provider(e.g. zipkin) may return it as a 64-bit hex
    99    // string. In this case, we need to convert it to a 128-bit hex string, padding left with zeros.
   100    std::string trace_id_hex = log_context.activeSpan().getTraceId();
   101    if (trace_id_hex.size() == 32) {
   102      *log_entry.mutable_trace_id() = absl::HexStringToBytes(trace_id_hex);
   103    } else if (trace_id_hex.size() == 16) {
   104      auto trace_id = absl::StrCat(Hex::uint64ToHex(0), trace_id_hex);
   105      *log_entry.mutable_trace_id() = absl::HexStringToBytes(trace_id);
   106    }
   107    std::string span_id_hex = log_context.activeSpan().getSpanId();
   108    if (!span_id_hex.empty()) {
   109      *log_entry.mutable_span_id() = absl::HexStringToBytes(span_id_hex);
   110    }
   111
   112    tls_slot_->getTyped<ThreadLocalLogger>().logger_->log(std::move(log_entry));
   113  }
