    15  FluentdAccessLoggerImpl::FluentdAccessLoggerImpl(Upstream::ThreadLocalCluster& cluster,
    16                                                   Tcp::AsyncTcpClientPtr client,
    17                                                   Event::Dispatcher& dispatcher,
    18                                                   const FluentdAccessLogConfig& config,
    19                                                   BackOffStrategyPtr backoff_strategy,
    20                                                   Stats::Scope& parent_scope)
    21      : tag_(config.tag()), id_(dispatcher.name()),
    22        max_connect_attempts_(
    23            config.has_retry_options() && config.retry_options().has_max_connect_attempts()
    24                ? absl::optional<uint32_t>(config.retry_options().max_connect_attempts().value())
    25                : absl::nullopt),
    26        stats_scope_(parent_scope.createScope(config.stat_prefix())),
    27        fluentd_stats_(
    28            {ACCESS_LOG_FLUENTD_STATS(POOL_COUNTER(*stats_scope_), POOL_GAUGE(*stats_scope_))}),
    29        cluster_(cluster), backoff_strategy_(std::move(backoff_strategy)), client_(std::move(client)),
    30        buffer_flush_interval_msec_(
    31            PROTOBUF_GET_MS_OR_DEFAULT(config, buffer_flush_interval, DefaultBufferFlushIntervalMs)),
    32        max_buffer_size_bytes_(
    33            PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, buffer_size_bytes, DefaultMaxBufferSize)),
    34        retry_timer_(dispatcher.createTimer([this]() -> void { onBackoffCallback(); })),
    35        flush_timer_(dispatcher.createTimer([this]() {
    36          flush();
    37          flush_timer_->enableTimer(buffer_flush_interval_msec_);
    38        })) {
    39    client_->setAsyncTcpClientCallbacks(*this);
    40    flush_timer_->enableTimer(buffer_flush_interval_msec_);
    41  }
    42
    43  void FluentdAccessLoggerImpl::onEvent(Network::ConnectionEvent event) {
    44    connecting_ = false;
    45
    46    if (event == Network::ConnectionEvent::Connected) {
    47      backoff_strategy_->reset();
    48      retry_timer_->disableTimer();
    49      flush();
    50    } else if (event == Network::ConnectionEvent::LocalClose ||
    51               event == Network::ConnectionEvent::RemoteClose) {
    52      ENVOY_LOG(debug, "upstream connection was closed");
    53      fluentd_stats_.connections_closed_.inc();
    54      maybeReconnect();
    55    }
    56  }
    57
    58  void FluentdAccessLoggerImpl::log(EntryPtr&& entry) {
    59    if (disconnected_ || approximate_message_size_bytes_ >= max_buffer_size_bytes_) {
    60      fluentd_stats_.entries_lost_.inc();
    61      // We will lose the data deliberately so the buffer doesn't grow infinitely.
    62      return;
    63    }
    64
    65    approximate_message_size_bytes_ += sizeof(entry->time_) + entry->record_.size();
    66    entries_.push_back(std::move(entry));
    67    fluentd_stats_.entries_buffered_.inc();
    68    if (approximate_message_size_bytes_ >= max_buffer_size_bytes_) {
    69      // If we exceeded the buffer limit, immediately flush the logs instead of waiting for
    70      // the next flush interval, to allow new logs to be buffered.
    71      flush();
    72    }
    73  }
    74
    75  void FluentdAccessLoggerImpl::flush() {
    76    ASSERT(!disconnected_);
    77
    78    if (entries_.size() == 0 || connecting_) {
    79      // nothing to send, or we're still waiting for an upstream connection.
    80      return;
    81    }
    82
    83    if (!client_->connected()) {
    84      connect();
    85      return;
    86    }
    87
    88    // Creating a Fluentd Forward Protocol Specification (v1) forward mode event as specified in:
    89    // https://github.com/fluent/fluentd/wiki/Forward-Protocol-Specification-v1#forward-mode
    90    MessagePackBuffer buffer;
    91    MessagePackPacker packer(buffer);
    92    packer.pack_array(2); // 1 - tag field, 2 - entries array.
    93    packer.pack(tag_);
    94    packer.pack_array(entries_.size());
    95
    96    for (auto& entry : entries_) {
    97      packer.pack_array(2); // 1 - time, 2 - record.
    98      packer.pack(entry->time_);
    99      const char* record_bytes = reinterpret_cast<const char*>(&entry->record_[0]);
   100      packer.pack_bin_body(record_bytes, entry->record_.size());
   101    }
   102
   103    Buffer::OwnedImpl data(buffer.data(), buffer.size());
   104    client_->write(data, false);
   105    fluentd_stats_.events_sent_.inc();
   106    clearBuffer();
   107  }
   108
   109  void FluentdAccessLoggerImpl::connect() {
   110    connect_attempts_++;
   111    if (!client_->connect()) {
   112      ENVOY_LOG(debug, "no healthy upstream");
   113      maybeReconnect();
   114      return;
   115    }
   116
   117    connecting_ = true;
   118  }
   119
   120  void FluentdAccessLoggerImpl::maybeReconnect() {
   121    if (max_connect_attempts_.has_value() && connect_attempts_ >= max_connect_attempts_) {
   122      ENVOY_LOG(debug, "max connection attempts reached");
   123      cluster_.info()->trafficStats()->upstream_cx_connect_attempts_exceeded_.inc();
   124      setDisconnected();
   125      return;
   126    }
   127
   128    uint64_t next_backoff_ms = backoff_strategy_->nextBackOffMs();
   129    retry_timer_->enableTimer(std::chrono::milliseconds(next_backoff_ms));
   130    ENVOY_LOG(debug, "reconnect attempt scheduled for {} ms", next_backoff_ms);
   131  }
   132
   133  void FluentdAccessLoggerImpl::onBackoffCallback() {
   134    fluentd_stats_.reconnect_attempts_.inc();
   135    this->connect();
   136  }
   137
   138  void FluentdAccessLoggerImpl::setDisconnected() {
   139    disconnected_ = true;
   140    clearBuffer();
   141    ASSERT(flush_timer_ != nullptr);
   142    flush_timer_->disableTimer();
   143  }
   144
   145  void FluentdAccessLoggerImpl::clearBuffer() {
   146    entries_.clear();
   147    approximate_message_size_bytes_ = 0;
   148  }
