   150  FluentdAccessLoggerCacheImpl::FluentdAccessLoggerCacheImpl(
   151      Upstream::ClusterManager& cluster_manager, Stats::Scope& parent_scope,
   152      ThreadLocal::SlotAllocator& tls)
   153      : cluster_manager_(cluster_manager),
   154        stats_scope_(parent_scope.createScope("access_logs.fluentd")), tls_slot_(tls.allocateSlot()) {
   155    tls_slot_->set(
   156        [](Event::Dispatcher& dispatcher) { return std::make_shared<ThreadLocalCache>(dispatcher); });
   157  }
