   159  FluentdAccessLoggerSharedPtr
   160  FluentdAccessLoggerCacheImpl::getOrCreateLogger(const FluentdAccessLogConfigSharedPtr config,
   161                                                  Random::RandomGenerator& random) {
   162    auto& cache = tls_slot_->getTyped<ThreadLocalCache>();
   163    const auto cache_key = MessageUtil::hash(*config);
   164    const auto it = cache.access_loggers_.find(cache_key);
   165    if (it != cache.access_loggers_.end() && !it->second.expired()) {
   166      return it->second.lock();
   167    }
   168
   169    auto* cluster = cluster_manager_.getThreadLocalCluster(config->cluster());
   170    if (!cluster) {
   171      return nullptr;
   172    }
   173
   174    auto client =
   175        cluster->tcpAsyncClient(nullptr, std::make_shared<const Tcp::AsyncTcpClientOptions>(false));
   176
   177    uint64_t base_interval_ms = DefaultBaseBackoffIntervalMs;
   178    uint64_t max_interval_ms = base_interval_ms * DefaultMaxBackoffIntervalFactor;
   179
   180    if (config->has_retry_options() && config->retry_options().has_backoff_options()) {
   181      base_interval_ms = PROTOBUF_GET_MS_OR_DEFAULT(config->retry_options().backoff_options(),
   182                                                    base_interval, DefaultBaseBackoffIntervalMs);
   183      max_interval_ms =
   184          PROTOBUF_GET_MS_OR_DEFAULT(config->retry_options().backoff_options(), max_interval,
   185                                     base_interval_ms * DefaultMaxBackoffIntervalFactor);
   186    }
   187
   188    BackOffStrategyPtr backoff_strategy = std::make_unique<JitteredExponentialBackOffStrategy>(
   189        base_interval_ms, max_interval_ms, random);
   190
   191    const auto logger = std::make_shared<FluentdAccessLoggerImpl>(
   192        *cluster, std::move(client), cache.dispatcher_, *config, std::move(backoff_strategy),
   193        *stats_scope_);
   194    cache.access_loggers_.emplace(cache_key, logger);
   195    return logger;
   196  }
   197
   198  FluentdAccessLog::FluentdAccessLog(AccessLog::FilterPtr&& filter, FluentdFormatterPtr&& formatter,
   199                                     const FluentdAccessLogConfigSharedPtr config,
   200                                     ThreadLocal::SlotAllocator& tls, Random::RandomGenerator& random,
   201                                     FluentdAccessLoggerCacheSharedPtr access_logger_cache)
   202      : ImplBase(std::move(filter)), formatter_(std::move(formatter)), tls_slot_(tls.allocateSlot()),
   203        config_(config), access_logger_cache_(access_logger_cache) {
   204    tls_slot_->set(
   205        [config = config_, &random, access_logger_cache = access_logger_cache_](Event::Dispatcher&) {
   206          return std::make_shared<ThreadLocalLogger>(
   207              access_logger_cache->getOrCreateLogger(config, random));
   208        });
   209  }
   210
   211  void FluentdAccessLog::emitLog(const Formatter::HttpFormatterContext& context,
   212                                 const StreamInfo::StreamInfo& stream_info) {
   213    auto msgpack = formatter_->format(context, stream_info);
   214    uint64_t time = std::chrono::duration_cast<std::chrono::seconds>(
   215                        stream_info.timeSource().systemTime().time_since_epoch())
   216                        .count();
   217    tls_slot_->getTyped<ThreadLocalLogger>().logger_->log(
   218        std::make_unique<Entry>(time, std::move(msgpack)));
   219  }
