    29        context.serverFactoryContext().localInfo(), nullptr /* listener_metadata */);
    30
    31    auto access_log = std::make_shared<WasmAccessLog>(plugin, nullptr, std::move(filter));
    32
    33    auto callback = [access_log, &context, plugin](Common::Wasm::WasmHandleSharedPtr base_wasm) {
    34      // NB: the Slot set() call doesn't complete inline, so all arguments must outlive this call.
    35      auto tls_slot = ThreadLocal::TypedSlot<PluginHandleSharedPtrThreadLocal>::makeUnique(
    36          context.serverFactoryContext().threadLocal());
    37      tls_slot->set([base_wasm, plugin](Event::Dispatcher& dispatcher) {
    38        return std::make_shared<PluginHandleSharedPtrThreadLocal>(
    39            Common::Wasm::getOrCreateThreadLocalPlugin(base_wasm, plugin, dispatcher));
    40      });
    41      access_log->setTlsSlot(std::move(tls_slot));
    42    };
    43
    44    if (!Common::Wasm::createWasm(
    45            plugin, context.scope().createScope(""), context.serverFactoryContext().clusterManager(),
    46            context.initManager(), context.serverFactoryContext().mainThreadDispatcher(),
    47            context.serverFactoryContext().api(), context.serverFactoryContext().lifecycleNotifier(),
    48            remote_data_provider_, std::move(callback))) {
    49      throw Common::Wasm::WasmException(
    50          fmt::format("Unable to create Wasm access log {}", plugin->name_));
    51    }
    52
    53    context.serverFactoryContext().api().customStatNamespaces().registerStatNamespace(
    54        Extensions::Common::Wasm::CustomStatNamespace);
    55    return access_log;
    56  }
