    81  /**
    82   * All stats for the grpc access logger. @see stats_macros.h
    83   */
    84  #define ALL_GRPC_ACCESS_LOGGER_STATS(COUNTER)                                                      \
    85    COUNTER(logs_written)                                                                            \
    86    COUNTER(logs_dropped)
    87
    88  /**
    89   * Wrapper struct for the access log stats. @see stats_macros.h
    90   */
    91  struct GrpcAccessLoggerStats {
    92    ALL_GRPC_ACCESS_LOGGER_STATS(GENERATE_COUNTER_STRUCT)
    93  };
    94
    95  /**
    96   * Base class for defining a gRPC logger with the `HttpLogProto` and `TcpLogProto` access log
    97   * entries and `LogRequest` and `LogResponse` gRPC messages.
    98   * The log entries and messages are distinct types to support batching of multiple access log
    99   * entries in a single gRPC messages that go on the wire.
   100   */
   101  template <typename HttpLogProto, typename TcpLogProto, typename LogRequest, typename LogResponse>
   102  class GrpcAccessLogger : public Detail::GrpcAccessLogger<HttpLogProto, TcpLogProto> {
   103  public:
   104    using Interface = Detail::GrpcAccessLogger<HttpLogProto, TcpLogProto>;
   105    GrpcAccessLogger(
   106        const envoy::extensions::access_loggers::grpc::v3::CommonGrpcAccessLogConfig& config,
   107        Event::Dispatcher& dispatcher, Stats::Scope& scope,
   108        absl::optional<std::string> access_log_prefix,
   109        std::unique_ptr<GrpcAccessLogClient<LogRequest, LogResponse>> client)
   110        : client_(std::move(client)), buffer_flush_interval_msec_(PROTOBUF_GET_MS_OR_DEFAULT(
   111                                          config, buffer_flush_interval, 1000)),
   112          flush_timer_(dispatcher.createTimer([this]() {
   113            flush();
   114            flush_timer_->enableTimer(buffer_flush_interval_msec_);
   115          })),
   116          max_buffer_size_bytes_(PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, buffer_size_bytes, 16384)) {
   117      flush_timer_->enableTimer(buffer_flush_interval_msec_);
   118      if (access_log_prefix.has_value()) {
   119        stats_ = std::make_unique<GrpcAccessLoggerStats>(GrpcAccessLoggerStats{
   120            ALL_GRPC_ACCESS_LOGGER_STATS(POOL_COUNTER_PREFIX(scope, access_log_prefix.value()))});
   121      }
   122    }
   123
   124    void log(HttpLogProto&& entry) override {
   125      if (!canLogMore()) {
   126        return;
   127      }
   128      approximate_message_size_bytes_ += entry.ByteSizeLong();
   129      addEntry(std::move(entry));
   130      if (approximate_message_size_bytes_ >= max_buffer_size_bytes_) {
   131        flush();
   132      }
   133    }
   134
   135    void log(TcpLogProto&& entry) override {
   136      approximate_message_size_bytes_ += entry.ByteSizeLong();
   137      addEntry(std::move(entry));
   138      if (approximate_message_size_bytes_ >= max_buffer_size_bytes_) {
   139        flush();
   140      }
   141    }
   142
   143  protected:
   144    std::unique_ptr<GrpcAccessLogClient<LogRequest, LogResponse>> client_;
   145    LogRequest message_;
   146
   147  private:
   148    virtual bool isEmpty() PURE;
   149    virtual void initMessage() PURE;
   150    virtual void addEntry(HttpLogProto&& entry) PURE;
   151    virtual void addEntry(TcpLogProto&& entry) PURE;
   152    virtual void clearMessage() { message_.Clear(); }
   153
   154    void flush() {
   155      if (isEmpty()) {
   156        // Nothing to flush.
   157        return;
   158      }
   159
   160      if (!client_->isConnected()) {
   161        initMessage();
   162      }
   163
   164      if (client_->log(message_)) {
   165        // Clear the message regardless of the success.
   166        approximate_message_size_bytes_ = 0;
   167        clearMessage();
   168      }
   169    }
   170
   171    // `canLogMore()` is only for streaming gRPC client only which could run into
   172    // AboveWriteBufferHighWatermark during `flush()` so that we tracks the log entries dropped caused
   173    // by that.
   174    //
   175    // For unary gRPC client, `canLogMore` always returns True[1][2] so `stats_` here is meaningless.
   176    //
   177    // [1]https://github.com/envoyproxy/envoy/blob/cd5ef906026160ec2cd766d8d18217e668c256d8/source/extensions/access_loggers/common/grpc_access_logger.h#L287.
   178    // [2]https://github.com/envoyproxy/envoy/blob/cd5ef906026160ec2cd766d8d18217e668c256d8/source/extensions/access_loggers/common/grpc_access_logger.h#L126
   179    bool canLogMore() {
   180      if (max_buffer_size_bytes_ == 0 || approximate_message_size_bytes_ < max_buffer_size_bytes_) {
   181        incLogsWrittenStats();
   182        return true;
   183      }
   184      flush();
   185      if (approximate_message_size_bytes_ < max_buffer_size_bytes_) {
   186        incLogsWrittenStats();
   187        return true;
   188      }
   189      incLogsDroppedStats();
   190      return false;
   191    }
   192
   193    void incLogsDroppedStats() {
   194      if (stats_) {
   195        stats_->logs_dropped_.inc();
   196      }
   197    }
   198
   199    void incLogsWrittenStats() {
   200      if (stats_) {
   201        stats_->logs_written_.inc();
   202      }
   203    }
   204
   205    const std::chrono::milliseconds buffer_flush_interval_msec_;
   206    const Event::TimerPtr flush_timer_;
   207    const uint64_t max_buffer_size_bytes_;
   208    uint64_t approximate_message_size_bytes_ = 0;
   209    std::unique_ptr<GrpcAccessLoggerStats> stats_ = nullptr;
   210  };
   211
   212  /**
   213   * Class for defining logger cache with the `GrpcAccessLogger` interface and
   214   * `ConfigProto` configuration.
   215   */
   216  template <typename GrpcAccessLogger, typename ConfigProto>
   217  class GrpcAccessLoggerCache : public Singleton::Instance,
   218                                public Detail::GrpcAccessLoggerCache<GrpcAccessLogger, ConfigProto> {
   219  public:
   220    using Interface = Detail::GrpcAccessLoggerCache<GrpcAccessLogger, ConfigProto>;
   221
   222    GrpcAccessLoggerCache(Grpc::AsyncClientManager& async_client_manager, Stats::Scope& scope,
   223                          ThreadLocal::SlotAllocator& tls)
   224        : scope_(scope), async_client_manager_(async_client_manager), tls_slot_(tls.allocateSlot()) {
   225      tls_slot_->set([](Event::Dispatcher& dispatcher) {
   226        return std::make_shared<ThreadLocalCache>(dispatcher);
   227      });
   228    }
   229
   230    typename GrpcAccessLogger::SharedPtr
   231    getOrCreateLogger(const ConfigProto& config, GrpcAccessLoggerType logger_type) override {
   232      // TODO(euroelessar): Consider cleaning up loggers.
   233      auto& cache = tls_slot_->getTyped<ThreadLocalCache>();
   234      const auto cache_key = std::make_pair(MessageUtil::hash(config), logger_type);
   235      const auto it = cache.access_loggers_.find(cache_key);
   236      if (it != cache.access_loggers_.end()) {
   237        return it->second;
   238      }
   239
   240      const auto logger = createLogger(config, cache.dispatcher_);
   241      cache.access_loggers_.emplace(cache_key, logger);
   242      return logger;
   243    }
   244
   245  protected:
   246    Stats::Scope& scope_;
   247    Grpc::AsyncClientManager& async_client_manager_;
   248
   249  private:
   250    /**
   251     * Per-thread cache.
   252     */
   253    struct ThreadLocalCache : public ThreadLocal::ThreadLocalObject {
   254      ThreadLocalCache(Event::Dispatcher& dispatcher) : dispatcher_(dispatcher) {}
   255
   256      Event::Dispatcher& dispatcher_;
   257      // Access loggers indexed by the hash of logger's configuration and logger type.
   258      absl::flat_hash_map<std::pair<std::size_t, Common::GrpcAccessLoggerType>,
   259                          typename GrpcAccessLogger::SharedPtr>
   260          access_loggers_;
   261    };
   262
   263    // Create the specific logger type for this cache.
   264    virtual typename GrpcAccessLogger::SharedPtr createLogger(const ConfigProto& config,
   265                                                              Event::Dispatcher& dispatcher) PURE;
   266
   267    ThreadLocal::SlotPtr tls_slot_;
   268  };
