    24
    25  // Note: OpenTelemetry protos are extra flexible and used also in the OT collector for batching and
    26  // so forth. As a result, some fields are repeated, but for our use case we assume the following
    27  // structure:
    28  // ExportLogsServiceRequest -> (single) ResourceLogs -> (single) ScopeLogs ->
    29  // (repeated) LogRecord.
    30  class GrpcAccessLoggerImpl
    31      : public Common::GrpcAccessLogger<
    32            opentelemetry::proto::logs::v1::LogRecord,
    33            // OpenTelemetry logging uses LogRecord for both HTTP and TCP, so protobuf::Empty is used
    34            // as an empty placeholder for the non-used addEntry method.
    35            // TODO(itamarkam): Don't cache OpenTelemetry loggers by type (HTTP/TCP).
    36            ProtobufWkt::Empty, opentelemetry::proto::collector::logs::v1::ExportLogsServiceRequest,
    37            opentelemetry::proto::collector::logs::v1::ExportLogsServiceResponse> {
    38  public:
    39    GrpcAccessLoggerImpl(
    40        const Grpc::RawAsyncClientSharedPtr& client,
    41        const envoy::extensions::access_loggers::open_telemetry::v3::OpenTelemetryAccessLogConfig&
    42            config,
    43        Event::Dispatcher& dispatcher, const LocalInfo::LocalInfo& local_info, Stats::Scope& scope);
    44
    45  private:
    46    class OTelLogRequestCallbacks
    47        : public Grpc::AsyncRequestCallbacks<
    48              opentelemetry::proto::collector::logs::v1::ExportLogsServiceResponse> {
    49    public:
    50      OTelLogRequestCallbacks(Common::GrpcAccessLoggerStats& stats, uint32_t sending_log_entries,
    51                              std::function<void(OTelLogRequestCallbacks*)> deletion)
    52          : stats_(stats), sending_log_entries_(sending_log_entries), deletion_(deletion) {}
    53
    54      void onCreateInitialMetadata(Http::RequestHeaderMap&) override {}
    55
    56      void onSuccess(Grpc::ResponsePtr<
    57                         opentelemetry::proto::collector::logs::v1::ExportLogsServiceResponse>&& resp,
    58                     Tracing::Span&) override {
    59        const uint32_t partial_rejected_log_entries =
    60            (resp && resp->has_partial_success()) ? resp->partial_success().rejected_log_records()
    61                                                  : 0;
    62        // For the unexpected case where partial rejected log entries are more than
    63        // sending log entries, we just regard all of them are dropped.
    64        if (sending_log_entries_ < partial_rejected_log_entries) {
    65          stats_.logs_dropped_.add(sending_log_entries_);
    66        } else {
    67          stats_.logs_dropped_.add(partial_rejected_log_entries);
    68          stats_.logs_written_.add(sending_log_entries_ - partial_rejected_log_entries);
    69        }
    70
    71        deletion_(this);
    72      }
    73
    74      void onFailure(Grpc::Status::GrpcStatus, const std::string&, Tracing::Span&) override {
    75        stats_.logs_dropped_.add(sending_log_entries_);
    76        deletion_(this);
    77      }
    78
    79      Common::GrpcAccessLoggerStats& stats_;
    80      const uint32_t sending_log_entries_;
    81      std::function<void(OTelLogRequestCallbacks*)> deletion_;
    82    };
