    50                GrpcCommon::optionalRetryPolicy(config.common_config()), genOTelCallbacksFactory())),
    51        stats_({ALL_GRPC_ACCESS_LOGGER_STATS(
    52            POOL_COUNTER_PREFIX(scope, absl::StrCat(GRPC_LOG_STATS_PREFIX, config.stat_prefix())))}) {
    53    initMessageRoot(config, local_info);
