    55
    56  std::function<GrpcAccessLoggerImpl::OTelLogRequestCallbacks&()>
    57  GrpcAccessLoggerImpl::genOTelCallbacksFactory() {
    58    return [this]() -> OTelLogRequestCallbacks& {
    59      auto callback = std::make_unique<OTelLogRequestCallbacks>(
    60          this->stats_, this->batched_log_entries_, [this](OTelLogRequestCallbacks* p) {
    61            if (this->callbacks_.contains(p)) {
    62              this->callbacks_.erase(p);
    63            }
    64          });
    65      OTelLogRequestCallbacks* ptr = callback.get();
    66      this->batched_log_entries_ = 0;
    67      this->callbacks_.emplace(ptr, std::move(callback));
    68      return *ptr;
    69    };
    70  }
    71  // See comment about the structure of repeated fields in the header file.
    72  void GrpcAccessLoggerImpl::initMessageRoot(
    73      const envoy::extensions::access_loggers::open_telemetry::v3::OpenTelemetryAccessLogConfig&
    74          config,
    75      const LocalInfo::LocalInfo& local_info) {
    76    auto* resource_logs = message_.add_resource_logs();
    77    root_ = resource_logs->add_scope_logs();
    78    auto* resource = resource_logs->mutable_resource();
    79    if (!config.disable_builtin_labels()) {
    80      *resource->add_attributes() = getStringKeyValue("log_name", config.common_config().log_name());
    81      *resource->add_attributes() = getStringKeyValue("zone_name", local_info.zoneName());
    82      *resource->add_attributes() = getStringKeyValue("cluster_name", local_info.clusterName());
    83      *resource->add_attributes() = getStringKeyValue("node_name", local_info.nodeName());
    84    }
    85
    86    for (const auto& pair : config.resource_attributes().values()) {
    87      *resource->add_attributes() = pair;
    88    }
    89  }
