   109  GrpcAccessLoggerImpl::SharedPtr GrpcAccessLoggerCacheImpl::createLogger(
   110      const envoy::extensions::access_loggers::open_telemetry::v3::OpenTelemetryAccessLogConfig&
   111          config,
   112      Event::Dispatcher& dispatcher) {
   113    // We pass skip_cluster_check=true to factoryForGrpcService in order to avoid throwing
   114    // exceptions in worker threads. Call sites of this getOrCreateLogger must check the cluster
   115    // availability via ClusterManager::checkActiveStaticCluster beforehand, and throw exceptions in
   116    // the main thread if necessary to ensure it does not throw here.
   117    auto factory_or_error = async_client_manager_.factoryForGrpcService(
   118        config.common_config().grpc_service(), scope_, true);
   119    THROW_IF_STATUS_NOT_OK(factory_or_error, throw);
   120    auto client = factory_or_error.value()->createUncachedRawAsyncClient();
   121    return std::make_shared<GrpcAccessLoggerImpl>(std::move(client), config, dispatcher, local_info_,
   122                                                  scope_);
   123  }
