    24  /**
    25   * A formatter for OpenTelemetry logs, which returns a KeyValueList proto.
    26   */
    27  class OpenTelemetryFormatter {
    28  public:
    29    OpenTelemetryFormatter(const ::opentelemetry::proto::common::v1::KeyValueList& format_mapping,
    30                           const std::vector<Formatter::CommandParserPtr>& commands);
