    39        absl::variant<const std::vector<Formatter::FormatterProviderPtr>,
    40                      const OpenTelemetryFormatMapWrapper, const OpenTelemetryFormatListWrapper>;
    41    // We use std::list to keep the order of the repeated "values" field in the OpenTelemetry
    42    // KeyValueList.
    43    using OpenTelemetryFormatMap = std::list<std::pair<std::string, OpenTelemetryFormatValue>>;
    44    using OpenTelemetryFormatMapPtr = std::unique_ptr<OpenTelemetryFormatMap>;
    45    struct OpenTelemetryFormatMapWrapper {
    46      OpenTelemetryFormatMapPtr value_;
    47    };
    48
    49    using OpenTelemetryFormatList = std::list<OpenTelemetryFormatValue>;
