    55    using OpenTelemetryFormatMapVisitor = OpenTelemetryFormatMapVisitorHelper<
    56        const std::function<::opentelemetry::proto::common::v1::AnyValue(
    57            const std::vector<Formatter::FormatterProviderPtr>&)>,
    58        const std::function<::opentelemetry::proto::common::v1::AnyValue(
    59            const OpenTelemetryFormatter::OpenTelemetryFormatMapWrapper&)>,
    60        const std::function<::opentelemetry::proto::common::v1::AnyValue(
    61            const OpenTelemetryFormatter::OpenTelemetryFormatListWrapper&)>>;
