    68      std::vector<Formatter::FormatterProviderPtr>
    69      toFormatStringValue(const std::string& string_format) const;
    70      OpenTelemetryFormatMapWrapper
    71      toFormatMapValue(const ::opentelemetry::proto::common::v1::KeyValueList& struct_format) const;
