    16  static const std::string DefaultUnspecifiedValueString = "-";
    17
    18  namespace Envoy {
    19  namespace Extensions {
    20  namespace AccessLoggers {
    21  namespace OpenTelemetry {
    22
    23  OpenTelemetryFormatter::OpenTelemetryFormatter(
    24      const ::opentelemetry::proto::common::v1::KeyValueList& format_mapping,
    25      const std::vector<Formatter::CommandParserPtr>& commands)
    26      : kv_list_output_format_(FormatBuilder(commands).toFormatMapValue(format_mapping)) {}
    27
    28  OpenTelemetryFormatter::OpenTelemetryFormatMapWrapper
    29  OpenTelemetryFormatter::FormatBuilder::toFormatMapValue(
    30      const ::opentelemetry::proto::common::v1::KeyValueList& kv_list_format) const {
    31    auto output = std::make_unique<OpenTelemetryFormatMap>();
    32    for (const auto& pair : kv_list_format.values()) {
    33      switch (pair.value().value_case()) {
    34      case ::opentelemetry::proto::common::v1::AnyValue::kStringValue:
    35        output->emplace_back(pair.key(), toFormatStringValue(pair.value().string_value()));
    36        break;
    37
    38      case ::opentelemetry::proto::common::v1::AnyValue::kKvlistValue:
    39        output->emplace_back(pair.key(), toFormatMapValue(pair.value().kvlist_value()));
    40        break;
    41
    42      case ::opentelemetry::proto::common::v1::AnyValue::kArrayValue:
    43        output->emplace_back(pair.key(), toFormatListValue(pair.value().array_value()));
    44        break;
    45
    46      default:
    47        throw EnvoyException("Only string values, nested key value lists and array values are "
    48                             "supported in OpenTelemetry access log format.");
    49      }
    50    }
    51    return {std::move(output)};
    52  }
    53
    54  OpenTelemetryFormatter::OpenTelemetryFormatListWrapper
    55  OpenTelemetryFormatter::FormatBuilder::toFormatListValue(
    56      const ::opentelemetry::proto::common::v1::ArrayValue& list_value_format) const {
    57    auto output = std::make_unique<OpenTelemetryFormatList>();
    58    for (const auto& value : list_value_format.values()) {
    59      switch (value.value_case()) {
    60      case ::opentelemetry::proto::common::v1::AnyValue::kStringValue:
    61        output->emplace_back(toFormatStringValue(value.string_value()));
    62        break;
    63
    64      case ::opentelemetry::proto::common::v1::AnyValue::kKvlistValue:
    65        output->emplace_back(toFormatMapValue(value.kvlist_value()));
    66        break;
    67
    68      case ::opentelemetry::proto::common::v1::AnyValue::kArrayValue:
    69        output->emplace_back(toFormatListValue(value.array_value()));
    70        break;
    71      default:
    72        throw EnvoyException("Only string values, nested key value lists and array values are "
    73                             "supported in OpenTelemetry access log format.");
    74      }
    75    }
    76    return {std::move(output)};
    77  }
    78
    79  std::vector<Formatter::FormatterProviderPtr>
    80  OpenTelemetryFormatter::FormatBuilder::toFormatStringValue(const std::string& string_format) const {
    81    return Formatter::SubstitutionFormatParser::parse(string_format, commands_);
    82  }
    83
    84  ::opentelemetry::proto::common::v1::AnyValue OpenTelemetryFormatter::providersCallback(
    85      const std::vector<Formatter::FormatterProviderPtr>& providers,
    86      const Formatter::HttpFormatterContext& context, const StreamInfo::StreamInfo& info) const {
    87    ASSERT(!providers.empty());
    88    ::opentelemetry::proto::common::v1::AnyValue output;
    89    std::vector<std::string> bits(providers.size());
    90
    91    std::transform(
    92        providers.begin(), providers.end(), bits.begin(),
    93        [&](const Formatter::FormatterProviderPtr& provider) {
    94          return provider->formatWithContext(context, info).value_or(DefaultUnspecifiedValueString);
    95        });
    96
    97    output.set_string_value(absl::StrJoin(bits, ""));
    98    return output;
    99  }
   100
   101  ::opentelemetry::proto::common::v1::AnyValue OpenTelemetryFormatter::openTelemetryFormatMapCallback(
   102      const OpenTelemetryFormatter::OpenTelemetryFormatMapWrapper& format_map,
   103      const OpenTelemetryFormatter::OpenTelemetryFormatMapVisitor& visitor) const {
   104    ::opentelemetry::proto::common::v1::AnyValue output;
   105    auto* kv_list = output.mutable_kvlist_value();
   106    for (const auto& pair : *format_map.value_) {
   107      ::opentelemetry::proto::common::v1::AnyValue value = absl::visit(visitor, pair.second);
   108      auto* kv = kv_list->add_values();
   109      kv->set_key(pair.first);
   110      *kv->mutable_value() = value;
   111    }
   112    return output;
   113  }
   114
   115  ::opentelemetry::proto::common::v1::AnyValue
   116  OpenTelemetryFormatter::openTelemetryFormatListCallback(
   117      const OpenTelemetryFormatter::OpenTelemetryFormatListWrapper& format_list,
   118      const OpenTelemetryFormatter::OpenTelemetryFormatMapVisitor& visitor) const {
   119    ::opentelemetry::proto::common::v1::AnyValue output;
   120    auto* array_value = output.mutable_array_value();
   121    for (const auto& val : *format_list.value_) {
   122      ::opentelemetry::proto::common::v1::AnyValue value = absl::visit(visitor, val);
   123      *array_value->add_values() = value;
   124    }
   125    return output;
   126  }
   127
   128  ::opentelemetry::proto::common::v1::KeyValueList
   129  OpenTelemetryFormatter::format(const Formatter::HttpFormatterContext& context,
   130                                 const StreamInfo::StreamInfo& info) const {
   131    OpenTelemetryFormatMapVisitor visitor{
   132        [&](const std::vector<Formatter::FormatterProviderPtr>& providers) {
   133          return providersCallback(providers, context, info);
   134        },
   135        [&, this](const OpenTelemetryFormatter::OpenTelemetryFormatMapWrapper& format_map) {
   136          return openTelemetryFormatMapCallback(format_map, visitor);
   137        },
   138        [&, this](const OpenTelemetryFormatter::OpenTelemetryFormatListWrapper& format_list) {
   139          return openTelemetryFormatListCallback(format_list, visitor);
   140        },
   141    };
   142    return openTelemetryFormatMapCallback(kv_list_output_format_, visitor).kvlist_value();
   143  }
