    22  // Helper function to convert from a BoringSSL textual representation of the
    23  // TLS version to the corresponding enum value used in gRPC access logs.
    24  TLSProperties_TLSVersion tlsVersionStringToEnum(const std::string& tls_version) {
    25    if (tls_version == "TLSv1") {
    26      return TLSProperties::TLSv1;
    27    } else if (tls_version == "TLSv1.1") {
    28      return TLSProperties::TLSv1_1;
    29    } else if (tls_version == "TLSv1.2") {
    30      return TLSProperties::TLSv1_2;
    31    } else if (tls_version == "TLSv1.3") {
    32      return TLSProperties::TLSv1_3;
    33    }
    34
    35    return TLSProperties::VERSION_UNSPECIFIED;
    36  }
