   161  void Utility::extractCommonAccessLogProperties(
   162      envoy::data::accesslog::v3::AccessLogCommon& common_access_log,
   163      const Http::RequestHeaderMap& request_header, const StreamInfo::StreamInfo& stream_info,
   164      const envoy::extensions::access_loggers::grpc::v3::CommonGrpcAccessLogConfig& config,
   165      AccessLog::AccessLogType access_log_type) {
   166    // TODO(mattklein123): Populate sample_rate field.
   167    if (stream_info.downstreamAddressProvider().remoteAddress() != nullptr) {
   168      Network::Utility::addressToProtobufAddress(
   169          *stream_info.downstreamAddressProvider().remoteAddress(),
   170          *common_access_log.mutable_downstream_remote_address());
   171    }
   172    if (stream_info.downstreamAddressProvider().directRemoteAddress() != nullptr) {
   173      Network::Utility::addressToProtobufAddress(
   174          *stream_info.downstreamAddressProvider().directRemoteAddress(),
   175          *common_access_log.mutable_downstream_direct_remote_address());
   176    }
   177    if (stream_info.downstreamAddressProvider().localAddress() != nullptr) {
   178      Network::Utility::addressToProtobufAddress(
   179          *stream_info.downstreamAddressProvider().localAddress(),
   180          *common_access_log.mutable_downstream_local_address());
   181    }
   182    if (!stream_info.downstreamAddressProvider().requestedServerName().empty()) {
   183      common_access_log.mutable_tls_properties()->set_tls_sni_hostname(
   184          MessageUtil::sanitizeUtf8String(
   185              stream_info.downstreamAddressProvider().requestedServerName()));
   186    }
   187    if (!stream_info.downstreamAddressProvider().ja3Hash().empty()) {
   188      common_access_log.mutable_tls_properties()->set_ja3_fingerprint(
   189          std::string(stream_info.downstreamAddressProvider().ja3Hash()));
   190    }
   191    if (stream_info.downstreamAddressProvider().sslConnection() != nullptr) {
   192      auto* tls_properties = common_access_log.mutable_tls_properties();
   193      const Ssl::ConnectionInfoConstSharedPtr downstream_ssl_connection =
   194          stream_info.downstreamAddressProvider().sslConnection();
   195
   196      auto* local_properties = tls_properties->mutable_local_certificate_properties();
   197      for (const auto& uri_san : downstream_ssl_connection->uriSanLocalCertificate()) {
   198        auto* local_san = local_properties->add_subject_alt_name();
   199        local_san->set_uri(MessageUtil::sanitizeUtf8String(uri_san));
   200      }
   201      local_properties->set_subject(
   202          MessageUtil::sanitizeUtf8String(downstream_ssl_connection->subjectLocalCertificate()));
   203
   204      auto* peer_properties = tls_properties->mutable_peer_certificate_properties();
   205      for (const auto& uri_san : downstream_ssl_connection->uriSanPeerCertificate()) {
   206        auto* peer_san = peer_properties->add_subject_alt_name();
   207        peer_san->set_uri(MessageUtil::sanitizeUtf8String(uri_san));
   208      }
   209
   210      peer_properties->set_subject(downstream_ssl_connection->subjectPeerCertificate());
   211      peer_properties->set_issuer(
   212          MessageUtil::sanitizeUtf8String(downstream_ssl_connection->issuerPeerCertificate()));
   213
   214      tls_properties->set_tls_session_id(
   215          MessageUtil::sanitizeUtf8String(downstream_ssl_connection->sessionId()));
   216      tls_properties->set_tls_version(
   217          tlsVersionStringToEnum(downstream_ssl_connection->tlsVersion()));
   218
   219      auto* local_tls_cipher_suite = tls_properties->mutable_tls_cipher_suite();
   220      local_tls_cipher_suite->set_value(downstream_ssl_connection->ciphersuiteId());
   221    }
   222    common_access_log.mutable_start_time()->MergeFrom(
   223        Protobuf::util::TimeUtil::NanosecondsToTimestamp(
   224            std::chrono::duration_cast<std::chrono::nanoseconds>(
   225                stream_info.startTime().time_since_epoch())
   226                .count()));
   227
   228    absl::optional<std::chrono::nanoseconds> dur = stream_info.requestComplete();
   229    if (dur) {
   230      common_access_log.mutable_duration()->MergeFrom(
   231          Protobuf::util::TimeUtil::NanosecondsToDuration(dur.value().count()));
   232    }
   233
   234    StreamInfo::TimingUtility timing(stream_info);
   235    dur = timing.lastDownstreamRxByteReceived();
   236    if (dur) {
   237      common_access_log.mutable_time_to_last_rx_byte()->MergeFrom(
   238          Protobuf::util::TimeUtil::NanosecondsToDuration(dur.value().count()));
   239    }
   240
   241    dur = timing.firstUpstreamTxByteSent();
   242    if (dur) {
   243      common_access_log.mutable_time_to_first_upstream_tx_byte()->MergeFrom(
   244          Protobuf::util::TimeUtil::NanosecondsToDuration(dur.value().count()));
   245    }
   246
   247    dur = timing.lastUpstreamTxByteSent();
   248    if (dur) {
   249      common_access_log.mutable_time_to_last_upstream_tx_byte()->MergeFrom(
   250          Protobuf::util::TimeUtil::NanosecondsToDuration(dur.value().count()));
   251    }
   252
   253    dur = timing.firstUpstreamRxByteReceived();
   254    if (dur) {
   255      common_access_log.mutable_time_to_first_upstream_rx_byte()->MergeFrom(
   256          Protobuf::util::TimeUtil::NanosecondsToDuration(dur.value().count()));
   257    }
   258
   259    dur = timing.lastUpstreamRxByteReceived();
   260    if (dur) {
   261      common_access_log.mutable_time_to_last_upstream_rx_byte()->MergeFrom(
   262          Protobuf::util::TimeUtil::NanosecondsToDuration(dur.value().count()));
   263    }
   264
   265    dur = timing.firstDownstreamTxByteSent();
   266    if (dur) {
   267      common_access_log.mutable_time_to_first_downstream_tx_byte()->MergeFrom(
   268          Protobuf::util::TimeUtil::NanosecondsToDuration(dur.value().count()));
   269    }
   270
   271    dur = timing.lastDownstreamTxByteSent();
   272    if (dur) {
   273      common_access_log.mutable_time_to_last_downstream_tx_byte()->MergeFrom(
   274          Protobuf::util::TimeUtil::NanosecondsToDuration(dur.value().count()));
   275    }
   276
   277    if (stream_info.upstreamInfo().has_value()) {
   278  #if defined(__GNUC__) && !defined(__clang__)
   279  #pragma GCC diagnostic push
   280  #pragma GCC diagnostic ignored "-Wdangling-reference"
   281  #endif
   282      const auto& upstream_info = stream_info.upstreamInfo().value().get();
   283  #if defined(__GNUC__) && !defined(__clang__)
   284  #pragma GCC diagnostic pop
   285  #endif
   286      if (upstream_info.upstreamHost() != nullptr) {
   287        Network::Utility::addressToProtobufAddress(
   288            *upstream_info.upstreamHost()->address(),
   289            *common_access_log.mutable_upstream_remote_address());
   290        common_access_log.set_upstream_cluster(upstream_info.upstreamHost()->cluster().name());
   291      }
   292      if (upstream_info.upstreamLocalAddress() != nullptr) {
   293        Network::Utility::addressToProtobufAddress(
   294            *upstream_info.upstreamLocalAddress(),
   295            *common_access_log.mutable_upstream_local_address());
   296      }
   297      if (!upstream_info.upstreamTransportFailureReason().empty()) {
   298        common_access_log.set_upstream_transport_failure_reason(
   299            upstream_info.upstreamTransportFailureReason());
   300      }
   301    }
   302    if (!stream_info.getRouteName().empty()) {
   303      common_access_log.set_route_name(stream_info.getRouteName());
   304    }
   305    if (stream_info.attemptCount().has_value()) {
   306      common_access_log.set_upstream_request_attempt_count(stream_info.attemptCount().value());
   307    }
   308    if (stream_info.connectionTerminationDetails().has_value()) {
   309      common_access_log.set_connection_termination_details(
   310          stream_info.connectionTerminationDetails().value());
   311    }
   312
   313    responseFlagsToAccessLogResponseFlags(common_access_log, stream_info);
   314    if (stream_info.dynamicMetadata().filter_metadata_size() > 0) {
   315      common_access_log.mutable_metadata()->MergeFrom(stream_info.dynamicMetadata());
   316    }
   317
   318    for (const auto& key : config.filter_state_objects_to_log()) {
   319      if (!(extractFilterStateData(stream_info.filterState(), key, common_access_log))) {
   320        if (stream_info.upstreamInfo().has_value() &&
   321            stream_info.upstreamInfo()->upstreamFilterState() != nullptr) {
   322          extractFilterStateData(*(stream_info.upstreamInfo()->upstreamFilterState()), key,
   323                                 common_access_log);
   324        }
   325      }
   326    }
   327
   328    Tracing::ReadOnlyHttpTraceContext trace_context(request_header);
   329    Tracing::CustomTagContext ctx{trace_context, stream_info};
   330    for (const auto& custom_tag : config.custom_tags()) {
   331      const auto tag_applier = Tracing::CustomTagUtility::createCustomTag(custom_tag);
   332      tag_applier->applyLog(common_access_log, ctx);
   333    }
   334
   335    // If the stream is not complete, then this log entry is intermediate log entry.
   336    if (!stream_info.requestComplete().has_value()) {
   337      common_access_log.set_intermediate_log_entry(true); // Deprecated field
   338    }
   339
   340    // Set stream unique id from the stream info.
   341    if (auto provider = stream_info.getStreamIdProvider(); provider.has_value()) {
   342      common_access_log.set_stream_id(std::string(provider->toStringView().value_or("")));
   343    }
   344
   345    if (const auto& reason = stream_info.downstreamTransportFailureReason(); !reason.empty()) {
   346      common_access_log.set_downstream_transport_failure_reason(reason);
   347    }
   348
   349    if (const auto& bytes_meter = stream_info.getDownstreamBytesMeter(); bytes_meter != nullptr) {
   350      common_access_log.set_downstream_wire_bytes_sent(bytes_meter->wireBytesSent());
   351      common_access_log.set_downstream_wire_bytes_received(bytes_meter->wireBytesReceived());
   352    }
   353    if (const auto& bytes_meter = stream_info.getUpstreamBytesMeter(); bytes_meter != nullptr) {
   354      common_access_log.set_upstream_wire_bytes_sent(bytes_meter->wireBytesSent());
   355      common_access_log.set_upstream_wire_bytes_received(bytes_meter->wireBytesReceived());
   356    }
   357
   358    common_access_log.set_access_log_type(access_log_type);
   359  }
   360
   361  bool extractFilterStateData(const StreamInfo::FilterState& filter_state, const std::string& key,
   362                              envoy::data::accesslog::v3::AccessLogCommon& common_access_log) {
   363    if (auto state = filter_state.getDataReadOnlyGeneric(key); state != nullptr) {
   364      ProtobufTypes::MessagePtr serialized_proto = state->serializeAsProto();
   365      if (serialized_proto != nullptr) {
   366        auto& filter_state_objects = *common_access_log.mutable_filter_state_objects();
   367        ProtobufWkt::Any& any = filter_state_objects[key];
   368        if (dynamic_cast<ProtobufWkt::Any*>(serialized_proto.get()) != nullptr) {
   369          any.Swap(dynamic_cast<ProtobufWkt::Any*>(serialized_proto.get()));
   370        } else {
   371          any.PackFrom(*serialized_proto);
   372        }
   373      }
   374      return true;
   375    }
   376    return false;
   377  }
