    59  /**
    60   * This is a file implementation geared for writing out access logs. It turn out that in certain
    61   * cases even if a standard file is opened with O_NONBLOCK, the kernel can still block when writing.
    62   * This implementation uses a flush thread per file, with the idea there aren't that many
    63   * files. If this turns out to be a good implementation we can potentially have a single flush
    64   * thread that flushes all files, but we will start with this.
    65   */
    66  class AccessLogFileImpl : public AccessLogFile {
    67  public:
    68    AccessLogFileImpl(Filesystem::FilePtr&& file, Event::Dispatcher& dispatcher,
    69                      Thread::BasicLockable& lock, AccessLogFileStats& stats,
    70                      std::chrono::milliseconds flush_interval_msec,
    71                      Thread::ThreadFactory& thread_factory);
    72    ~AccessLogFileImpl() override;
    73
    74    // AccessLog::AccessLogFile
    75    void write(absl::string_view data) override;
    76
    77    /**
    78     * Reopen file asynchronously.
    79     * This only sets reopen flag, actual reopen operation is delayed.
    80     * Reopen happens before the next write operation.
    81     */
    82    void reopen() override;
    83    void flush() override;
    84
    85  private:
    86    void doWrite(Buffer::Instance& buffer);
    87    void flushThreadFunc();
    88    void createFlushStructures();
    89
    90    // Minimum size before the flush thread will be told to flush.
    91    static const uint64_t MIN_FLUSH_SIZE = 1024 * 64;
    92
    93    Filesystem::FilePtr file_;
    94
    95    // These locks are always acquired in the following order if multiple locks are held:
    96    //    1) write_lock_
    97    //    2) flush_lock_
    98    //    3) file_lock_
    99    Thread::BasicLockable& file_lock_;      // This lock is used only by the flush thread when writing
   100                                            // to disk. This is used to make sure that file blocks do
   101                                            // not get interleaved by multiple processes writing to
   102                                            // the same file during hot-restart.
   103    Thread::MutexBasicLockable flush_lock_; // This lock is used to prevent simultaneous flushes from
   104                                            // the flush thread and a synchronous flush. This protects
   105                                            // concurrent access to the about_to_write_buffer_, fd_,
   106                                            // and all other data used during flushing and file
   107                                            // re-opening.
   108    Thread::MutexBasicLockable
   109        write_lock_; // The lock is used when filling the flush buffer. It allows
   110                     // multiple threads to write to the same file at relatively
   111                     // high performance. It is always local to the process.
   112    Thread::ThreadPtr flush_thread_;
   113    Thread::CondVar flush_event_;
   114    bool flush_thread_exit_ ABSL_GUARDED_BY(write_lock_){false};
   115    bool reopen_file_ ABSL_GUARDED_BY(write_lock_){false};
   116    Buffer::OwnedImpl
   117        flush_buffer_ ABSL_GUARDED_BY(write_lock_); // This buffer is used by multiple threads. It
   118                                                    // gets filled and then flushed either when max
   119                                                    // size is reached or when a timer fires.
   120    // TODO(jmarantz): this should be ABSL_GUARDED_BY(flush_lock_) but the analysis cannot poke
   121    // through the std::make_unique assignment. I do not believe it's possible to annotate this
   122    // properly now due to limitations in the clang thread annotation analysis.
   123    Buffer::OwnedImpl about_to_write_buffer_; // This buffer is used only by the flush thread. Data
   124                                              // is moved from flush_buffer_ under lock, and then
   125                                              // the lock is released so that flush_buffer_ can
   126                                              // continue to fill. This buffer is then used for the
   127                                              // final write to disk.
   128    Event::TimerPtr flush_timer_;
   129    Thread::ThreadFactory& thread_factory_;
   130    const std::chrono::milliseconds flush_interval_msec_; // Time interval buffer gets flushed no
   131                                                          // matter if it reached the MIN_FLUSH_SIZE
   132                                                          // or not.
   133    AccessLogFileStats& stats_;
   134  };
