    35  absl::StatusOr<AccessLogFileSharedPtr>
    36  AccessLogManagerImpl::createAccessLog(const Filesystem::FilePathAndType& file_info) {
    37    auto file = api_.fileSystem().createFile(file_info);
    38    std::string file_name = file->path();
    39    if (access_logs_.count(file_name)) {
    40      return access_logs_[file_name];
    41    }
    42
    43    Api::IoCallBoolResult open_result = file->open(default_flags);
    44    if (!open_result.return_value_) {
    45      return absl::InvalidArgumentError(fmt::format("unable to open file '{}': {}", file_name,
    46                                                    open_result.err_->getErrorDetails()));
    47    }
    48
    49    access_logs_[file_name] =
    50        std::make_shared<AccessLogFileImpl>(std::move(file), dispatcher_, lock_, file_stats_,
    51                                            file_flush_interval_msec_, api_.threadFactory());
    52    return access_logs_[file_name];
