    58                                       Thread::ThreadFactory& thread_factory)
    59      : file_(std::move(file)), file_lock_(lock),
    60        flush_timer_(dispatcher.createTimer([this]() -> void {
    61          stats_.flushed_by_timer_.inc();
    62          flush_event_.notifyOne();
    63          flush_timer_->enableTimer(flush_interval_msec_);
