    74
    75  AccessLogFileImpl::~AccessLogFileImpl() {
    76    {
    77      Thread::LockGuard lock(write_lock_);
    78      flush_thread_exit_ = true;
    79      flush_event_.notifyOne();
    80    }
    81
    82    if (flush_thread_ != nullptr) {
    83      flush_thread_->join();
    84    }
    85
    86    // Flush any remaining data. If file was not opened for some reason, skip flushing part.
    87    if (file_->isOpen()) {
    88      if (flush_buffer_.length() > 0) {
    89        doWrite(flush_buffer_);
    90      }
    91      const Api::IoCallBoolResult result = file_->close();
    92      ASSERT(result.return_value_, fmt::format("unable to close file '{}': {}", file_->path(),
    93                                               result.err_->getErrorDetails()));
    94    }
