    96
    97  void AccessLogFileImpl::doWrite(Buffer::Instance& buffer) {
    98    Buffer::RawSliceVector slices = buffer.getRawSlices();
    99
   100    // We must do the actual writes to disk under lock, so that we don't intermix chunks from
   101    // different AccessLogFileImpl pointing to the same underlying file. This can happen either via
   102    // hot restart or if calling code opens the same underlying file into a different
   103    // AccessLogFileImpl in the same process.
   104    // TODO PERF: Currently, we use a single cross process lock to serialize all disk writes. This
   105    //            will never block network workers, but does mean that only a single flush thread can
   106    //            actually flush to disk. In the future it would be nice if we did away with the cross
   107    //            process lock or had multiple locks.
   108    {
   109      Thread::LockGuard lock(file_lock_);
   110      for (const Buffer::RawSlice& slice : slices) {
   111        absl::string_view data(static_cast<char*>(slice.mem_), slice.len_);
   112        const Api::IoCallSizeResult result = file_->write(data);
   113        if (result.ok() && result.return_value_ == static_cast<ssize_t>(slice.len_)) {
   114          stats_.write_completed_.inc();
   115        } else {
   116          // Probably disk full.
   117          stats_.write_failed_.inc();
   118        }
   119      }
   120    }
   121
   122    stats_.write_total_buffered_.sub(buffer.length());
   123    buffer.drain(buffer.length());
   124  }
   125
   126  void AccessLogFileImpl::flushThreadFunc() {
   127
   128    // Transfer the action from `reopen_file_` to this variable so that `reopen_file_` is only
   129    // accessed while holding the mutex while the actual operation is performed while not holding the
   130    // mutex.
   131    bool do_reopen = false;
   132
   133    while (true) {
   134      std::unique_lock<Thread::BasicLockable> flush_lock;
   135
   136      {
   137        Thread::LockGuard write_lock(write_lock_);
   138
   139        // flush_event_ can be woken up either by large enough flush_buffer or by timer.
   140        // In case it was timer, flush_buffer_ can be empty.
   141        //
   142        // Note: do not stop waiting when only `do_reopen` is true. In this case, we tried to
   143        // reopen and failed. We don't want to retry this in a tight loop, so wait for the next
   144        // event (timer or flush).
   145        while (flush_buffer_.length() == 0 && !flush_thread_exit_ && !reopen_file_) {
   146          // CondVar::wait() does not throw, so it's safe to pass the mutex rather than the guard.
   147          flush_event_.wait(write_lock_);
   148        }
   149
   150        if (flush_thread_exit_) {
   151          return;
   152        }
   153
   154        flush_lock = std::unique_lock<Thread::BasicLockable>(flush_lock_);
   155        about_to_write_buffer_.move(flush_buffer_);
   156        ASSERT(flush_buffer_.length() == 0);
   157
   158        if (reopen_file_) {
   159          do_reopen = true;
   160          reopen_file_ = false;
   161        }
   162      }
   163
   164      if (do_reopen) {
   165        if (file_->isOpen()) {
   166          const Api::IoCallBoolResult result = file_->close();
   167          ASSERT(result.return_value_, fmt::format("unable to close file '{}': {}", file_->path(),
   168                                                   result.err_->getErrorDetails()));
   169        }
   170        const Api::IoCallBoolResult open_result = file_->open(default_flags);
   171        if (!open_result.return_value_) {
   172          stats_.reopen_failed_.inc();
   173        } else {
   174          do_reopen = false;
   175        }
   176      }
   177      // doWrite no matter file isOpen, if not, we can drain buffer
   178      doWrite(about_to_write_buffer_);
   179    }
   180  }
   181
   182  void AccessLogFileImpl::flush() {
   183    std::unique_lock<Thread::BasicLockable> flush_buffer_lock;
   184
   185    {
   186      Thread::LockGuard write_lock(write_lock_);
   187
   188      // flush_lock_ must be held while checking this or else it is
   189      // possible that flushThreadFunc() has already moved data from
   190      // flush_buffer_ to about_to_write_buffer_, has unlocked write_lock_,
   191      // but has not yet completed doWrite(). This would allow flush() to
   192      // return before the pending data has actually been written to disk.
   193      flush_buffer_lock = std::unique_lock<Thread::BasicLockable>(flush_lock_);
   194
   195      if (flush_buffer_.length() == 0) {
   196        return;
   197      }
   198
   199      about_to_write_buffer_.move(flush_buffer_);
   200      ASSERT(flush_buffer_.length() == 0);
   201    }
   202
   203    doWrite(about_to_write_buffer_);
   204  }
   205
   206  void AccessLogFileImpl::write(absl::string_view data) {
   207    Thread::LockGuard lock(write_lock_);
   208
   209    if (flush_thread_ == nullptr) {
   210      createFlushStructures();
   211    }
   212
   213    stats_.write_buffered_.inc();
   214    stats_.write_total_buffered_.add(data.length());
   215    flush_buffer_.add(data.data(), data.size());
   216    if (flush_buffer_.length() > MIN_FLUSH_SIZE) {
   217      flush_event_.notifyOne();
   218    }
   219  }
   220
   221  void AccessLogFileImpl::createFlushStructures() {
   222    flush_thread_ = thread_factory_.createThread([this]() -> void { flushThreadFunc(); },
   223                                                 Thread::Options{"AccessLogFlush"});
   224  }
