    61  template <typename LogRequest, typename LogResponse>
    62  class UnaryGrpcAccessLogClient : public GrpcAccessLogClient<LogRequest, LogResponse> {
    63  public:
    64    typedef std::function<Grpc::AsyncRequestCallbacks<LogResponse>&()> AsyncRequestCallbacksFactory;
    65
    66    UnaryGrpcAccessLogClient(const Grpc::RawAsyncClientSharedPtr& client,
    67                             const Protobuf::MethodDescriptor& service_method,
    68                             OptRef<const envoy::config::core::v3::RetryPolicy> retry_policy,
    69                             AsyncRequestCallbacksFactory callback_factory)
    70        : GrpcAccessLogClient<LogRequest, LogResponse>(client, service_method, retry_policy),
    71          callbacks_factory_(callback_factory) {}
    72
    73    bool isConnected() override { return false; }
    74
    75    bool log(const LogRequest& request) override {
    76      GrpcAccessLogClient<LogRequest, LogResponse>::client_->send(
    77          GrpcAccessLogClient<LogRequest, LogResponse>::service_method_, request,
    78          callbacks_factory_(), Tracing::NullSpan::instance(),
    79          GrpcAccessLogClient<LogRequest, LogResponse>::opts_);
    80      return true;
    81    }
    82
    83  private:
    84    AsyncRequestCallbacksFactory callbacks_factory_;
    85  };
    86
    87  template <typename LogRequest, typename LogResponse>
    88  class StreamingGrpcAccessLogClient : public GrpcAccessLogClient<LogRequest, LogResponse> {
    89  public:
    90    StreamingGrpcAccessLogClient(const Grpc::RawAsyncClientSharedPtr& client,
    91                                 const Protobuf::MethodDescriptor& service_method,
    92                                 OptRef<const envoy::config::core::v3::RetryPolicy> retry_policy)
    93        : GrpcAccessLogClient<LogRequest, LogResponse>(client, service_method, retry_policy) {}
    94
    95  public:
    96    struct LocalStream : public Grpc::AsyncStreamCallbacks<LogResponse> {
    97      LocalStream(StreamingGrpcAccessLogClient& parent) : parent_(parent) {}
    98
    99      // Grpc::AsyncStreamCallbacks
   100      void onCreateInitialMetadata(Http::RequestHeaderMap&) override {}
   101      void onReceiveInitialMetadata(Http::ResponseHeaderMapPtr&&) override {}
   102      void onReceiveMessage(std::unique_ptr<LogResponse>&&) override {}
   103      void onReceiveTrailingMetadata(Http::ResponseTrailerMapPtr&&) override {}
   104      void onRemoteClose(Grpc::Status::GrpcStatus, const std::string&) override {
   105        ASSERT(parent_.stream_ != nullptr);
   106        if (parent_.stream_->stream_ != nullptr) {
   107          // Only reset if we have a stream. Otherwise we had an inline failure and we will clear the
   108          // stream data in send().
   109          parent_.stream_.reset();
   110        }
   111      }
   112
   113      StreamingGrpcAccessLogClient& parent_;
   114      Grpc::AsyncStream<LogRequest> stream_{};
   115    };
   116
   117    bool isConnected() override { return stream_ != nullptr && stream_->stream_ != nullptr; }
   118
   119    bool log(const LogRequest& request) override {
   120      if (!stream_) {
   121        stream_ = std::make_unique<LocalStream>(*this);
   122      }
   123
   124      if (stream_->stream_ == nullptr) {
   125        stream_->stream_ = GrpcAccessLogClient<LogRequest, LogResponse>::client_->start(
   126            GrpcAccessLogClient<LogRequest, LogResponse>::service_method_, *stream_,
   127            GrpcAccessLogClient<LogRequest, LogResponse>::opts_);
   128      }
   129
   130      if (stream_->stream_ != nullptr) {
   131        if (stream_->stream_->isAboveWriteBufferHighWatermark()) {
   132          return false;
   133        }
   134        stream_->stream_->sendMessage(request, false);
   135      } else {
   136        // Clear out the stream data due to stream creation failure.
   137        stream_.reset();
   138      }
   139      return true;
   140    }
   141
   142    std::unique_ptr<LocalStream> stream_;
   143  };
